import asyncio

root = "/tmp/ironclaw_live_codeact_shims/yaml_workflow_update_raw"

def strip_numbered(text):
    out = []
    for line in text.splitlines():
        sep = line.find("│")
        if sep >= 0:
            out.append(line[sep + 1 :].lstrip(" "))
        else:
            out.append(line)
    return "\n".join(out)

glob_res = await glob(
    max_results=200,
    path=root,
    pattern="**/.github/workflows/*.yml",
)

paths = sorted([root + "/" + p for p in glob_res["files"]])
modified = []

reads = await asyncio.gather(*[
    read_file(path=p, offset=1, limit=2000) for p in paths
])

for p, rf in zip(paths, reads):
    original = strip_numbered(rf["content"])
    updated = original.replace("actions/checkout@v3", "actions/checkout@v4")
    if updated != original:
        await write_file(path=p, content=updated)
        modified.append(p.split("/")[-1])

verify_reads = await asyncio.gather(*[
    read_file(path=p, offset=1, limit=2000) for p in paths
])

for p, rf in zip(paths, verify_reads):
    text = strip_numbered(rf["content"])
    if "actions/checkout@v3" in text:
        raise Exception("verification failed: still contains v3 in " + p)

